/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ks_facturas` (
  `FC_IDFACTURA_PK` int NOT NULL AUTO_INCREMENT,
  `FC_NUMERO_FACTURA` varchar(50) NOT NULL,
  `FC_FECHA` datetime NOT NULL,
  `FC_CLIENTE_NOMBRE` varchar(255) DEFAULT NULL,
  `FC_CLIENTE_TELEFONO` varchar(20) DEFAULT NULL,
  `FC_TOTAL` decimal(15,2) DEFAULT '0.00',
  `FC_ESTADO` enum('PENDIENTE','PAGADO','CANCELADO') DEFAULT 'PENDIENTE',
  `SC_IDSUCURSAL_FK` int NOT NULL,
  `TR_IDCAJERO_FK` int NOT NULL,
  `FC_TIPO_CLIENTE` enum('CLIENTE','TECNICO') DEFAULT 'CLIENTE',
  `TR_IDCLIENTE_FK` int DEFAULT NULL,
  `FC_EVIDENCIA_FISICA_URL` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`FC_IDFACTURA_PK`),
  UNIQUE KEY `FC_NUMERO_FACTURA` (`FC_NUMERO_FACTURA`),
  KEY `FK_FACTURA_SUCURSAL` (`SC_IDSUCURSAL_FK`),
  KEY `FK_FACTURA_CAJERO` (`TR_IDCAJERO_FK`),
  KEY `FK_FACTURA_CLIENTE_TECNICO` (`TR_IDCLIENTE_FK`),
  CONSTRAINT `FK_FACTURA_CAJERO` FOREIGN KEY (`TR_IDCAJERO_FK`) REFERENCES `ks_trabajadores` (`TR_IDTRABAJADOR_PK`),
  CONSTRAINT `FK_FACTURA_CLIENTE_TECNICO` FOREIGN KEY (`TR_IDCLIENTE_FK`) REFERENCES `ks_trabajadores` (`TR_IDTRABAJADOR_PK`),
  CONSTRAINT `FK_FACTURA_SUCURSAL` FOREIGN KEY (`SC_IDSUCURSAL_FK`) REFERENCES `ks_sucursales` (`SC_IDSUCURSAL_PK`)
) ENGINE=InnoDB AUTO_INCREMENT=704 DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

