--
-- Table structure for table `ks_vales`
--

DROP TABLE IF EXISTS `ks_vales`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ks_vales` (
  `vl_idvale_pk` int NOT NULL AUTO_INCREMENT,
  `TR_IDTRABAJADOR_FK` int NOT NULL,
  `vl_monto` decimal(15,2) NOT NULL,
  `vl_fecha` date DEFAULT NULL,
  `vl_estado` enum('PENDIENTE','DESCONTADO','ANULADO') DEFAULT 'PENDIENTE',
  `NM_IDNOMINA_FK` int DEFAULT NULL,
  `vl_observaciones` text,
  `vl_fecha_creacion` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `vl_cuotas` int NOT NULL DEFAULT '1',
  `vl_cuotas_pagadas` int NOT NULL DEFAULT '0',
  `vl_fecha_desembolso` date DEFAULT NULL,
  `vl_fecha_inicio_cobro` date DEFAULT NULL,
  `sc_idsucursal_fk` int NOT NULL,
  PRIMARY KEY (`vl_idvale_pk`),
  KEY `FK_ADELANTO_NOMINA` (`NM_IDNOMINA_FK`),
  KEY `IDX_ADELANTO_TRABAJADOR` (`TR_IDTRABAJADOR_FK`),
  KEY `IDX_ADELANTO_ESTADO` (`vl_estado`),
  KEY `fk_vales_sucursal` (`sc_idsucursal_fk`),
  CONSTRAINT `FK_ADELANTO_NOMINA` FOREIGN KEY (`NM_IDNOMINA_FK`) REFERENCES `ks_nominas` (`NM_IDNOMINA_PK`) ON DELETE SET NULL,
  CONSTRAINT `FK_ADELANTO_TRABAJADOR` FOREIGN KEY (`TR_IDTRABAJADOR_FK`) REFERENCES `ks_trabajadores` (`TR_IDTRABAJADOR_PK`) ON DELETE CASCADE,
  CONSTRAINT `fk_vales_sucursal` FOREIGN KEY (`sc_idsucursal_fk`) REFERENCES `ks_sucursales` (`SC_IDSUCURSAL_PK`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=latin1;
/*!40101 SET character_set_client = @saved_cs_client */;

